SELECT season, total_wins, AVG(turnovers) AS average_turnovers
FROM season_stats
GROUP BY season;

SELECT AVG(points_scored) AS average_points_scored
FROM season_stats
WHERE season = '2019-20';

SELECT season, total_wins, total_losses
FROM season_stats
ORDER BY total_wins DESC;

SELECT SUM(points_scored) AS total_points_scored
FROM season_stats
WHERE season = '2019-20';

SELECT COUNT(DISTINCT school_name) AS distinct_school_count, SUM(enrollment) AS total_enrollment
FROM schools
WHERE location = 'Austin';

SELECT AVG(points_per_game) AS average_points_per_game
FROM performance_metrics
WHERE season BETWEEN '2019-20' AND '2020-21';

SELECT AVG(points_per_game) AS average_points_per_game
FROM performance_metrics
WHERE season = '2019-20';
